import redis
import json

class AdvancedRedisClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db, decode_responses=True)
    
    def execute_lua_script(self, lua_script, keys=None, args=None):
        """
        Execute Lua script with dynamic cache operations
        """
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        try:
            result = self.redis_client.eval(lua_script, len(keys), *keys, *args)
            return result
        except redis.exceptions.RedisError as e:
            raise Exception(f"Redis error: {str(e)}")
        except Exception as e:
            raise Exception(f"Script execution error: {str(e)}")
    
    def execute_script_with_params(self, script_code, params=None):
        """
        Execute Lua script with user parameters
        """
        if params is None:
            params = {}
        
        # Convert params to list for Redis EVAL
        script_args = []
        for key, value in params.items():
            if isinstance(value, (dict, list)):
                script_args.append(json.dumps(value))
            else:
                script_args.append(str(value))
        
        return self.execute_lua_script(script_code, [], script_args)

